class Admin_Model_CategoryAttachment extends Admin_Model_Base_CategoryAttachment
{

    public static function getAttachmentByAttachmentID(int $attachmentID) {
        return Doctrine_Query::create()
            ->from('Admin_Model_CategoryAttachment ca')
            ->where('ca.ID = ?', $attachmentID)
            ->fetchOne();
    }

    public static function getAttachmentsByCategoryID(int $categoryID): Doctrine_Collection {
        return Doctrine_Query::create()
            ->from('Admin_Model_CategoryAttachment ca')
            ->where('ca.Category_ID = ?', $categoryID)
            ->execute();
    }

    public static function getAttachmentsByCategoryCode($categoryCode) {
        $category = Admin_Model_Category::getCategoryByCode($categoryCode);
        if(!$category) {
            return null;
        }
        return Doctrine_Query::create()
            ->from('Admin_Model_CategoryAttachment ca')
            ->where('ca.Category_ID = ?', $category->ID)
            ->execute();
    }

}